imp_line_3w=zeros(4,4,nline);
for l=1:nline
    for i=1:3
        for j=1:3
            if i==j
              imp_line(i,j,l)=(2*zp(l)+zz(l))/3;
            else
              imp_line(i,j,l)=(zz(l)-zp(l))/3;
            end
        end
    end
    dummy=zeros(4,4);
    dummy(1:3,1:3)=inv(imp_line(:,:,l));
    adm_line(:,:,l)=dummy;
    dummy1=zeros(4,4);
    dummy1(1:3,1:3)=(imp_line(:,:,l));
    imp_line_3w(:,:,l)=dummy1;
